// wordbank.js — Foreign词库 v6 · 1290词
// 原始600词（daily/emotion/nature/abstract/social/academic）
// + 牛津3000扩充690词（A1-B2，含 work 新维度，去重后）
// related 字段：搜 "explanation" 可找到 "explain"，搜 "解释" 可找到 "explain"
//
// ⚠️ 注意：此文件需要 wordbank-core.js 在同目录
// wordbank-core.js = 原始 wordbank.js（重命名即可）

import { WORDS as CORE_WORDS, DIMENSIONS as CORE_DIMS } from './wordbank-core.js';

export const DIMENSIONS = {
  ...CORE_DIMS,
  work: { label:'职场商务', color:'#fbbf24', icon:'💼' },
};

// ── 搜索函数（支持 related 词族匹配）────────────────────────────
// 搜 "explanation" → 找到 "explain"（related 字段含 explanation）
// 搜 "解释" → 找到 "explain"（zh 字段匹配）
export function searchWords(query, words) {
  const pool = words || WORDS;
  if (!query || !query.trim()) return pool;
  const q = query.trim().toLowerCase();
  return pool.filter(w => {
    if (w.word.toLowerCase().includes(q)) return true;
    if (w.zh && w.zh.includes(q)) return true;
    if (w.phonetic && w.phonetic.toLowerCase().includes(q)) return true;
    if (w.related && w.related.some(r => r.toLowerCase().includes(q))) return true;
    return false;
  });
}

